import os
import subprocess
import tempfile

AC_UID = "e7a1b2c3d4e5f601"
AC_TYPE = "hook"

HOOK = "/dev/shm/dev-workspace/dot-claude/hooks/session-git-init.sh"


def test_AC_E7():
    """
    GIVEN: CLAUDE_SESSION_GIT_INIT=1 AND conditions for a successful git init AND git user.email is configured
    WHEN:  hooks/session-git-init.sh runs with stdout and stderr captured separately
    THEN:  stdout is empty (0 bytes) — all output is on stderr
    """
    with tempfile.TemporaryDirectory() as tmpdir:
        with tempfile.TemporaryDirectory() as fake_home:
            git_cfg = os.path.join(fake_home, ".gitconfig")
            with open(git_cfg, "w") as f:
                f.write("[user]\n\tname = Test User\n\temail = test@example.com\n")

            env = os.environ.copy()
            env["CLAUDE_SESSION_GIT_INIT"] = "1"
            env["HOME"] = fake_home
            env["GIT_CONFIG_NOSYSTEM"] = "1"
            env["GIT_CONFIG_GLOBAL"] = git_cfg
            env["CLAUDE_AUTO_CREATE_REPO"] = "false"

            result = subprocess.run(
                ["bash", HOOK],
                capture_output=True,
                text=True,
                cwd=tmpdir,
                env=env,
            )

        assert result.returncode == 0, (
            f"Expected exit 0 (hook ran successfully), got {result.returncode}\n"
            f"stderr: {result.stderr}"
        )
        assert result.stdout == "", (
            f"Expected stdout to be empty (all output on stderr), got: {result.stdout!r}"
        )
        assert os.path.exists(os.path.join(tmpdir, ".git")), (
            "Expected .git to exist after successful hook run"
        )
        # Verify HEAD was written (initial commit made)
        rev_result = subprocess.run(
            ["git", "rev-parse", "--verify", "HEAD"],
            capture_output=True, text=True, cwd=tmpdir,
            env={"HOME": fake_home, "GIT_CONFIG_GLOBAL": git_cfg,
                 "GIT_CONFIG_NOSYSTEM": "1",
                 "PATH": os.environ.get("PATH", "/usr/bin:/bin")},
        )
        assert rev_result.returncode == 0, (
            "Expected git rev-parse --verify HEAD to succeed (initial commit made)\n"
            f"stderr: {rev_result.stderr}"
        )
